1	package checks
2	
3	import (
4		"bytes"
5		"fmt"
6		"os"
7		"path"
8		"path/filepath"
9		"sort"
10		"strings"
11	
12		"gopkg.in/yaml.v3"
13	)
14	
15	// LoadDir reads all *.yaml and *.yml files in dir as Check definitions.
16	// If dir does not exist, returns (nil, nil) — projects without a checks
17	// directory have no checks. Any unreadable file, malformed YAML, or
18	// unknown field is reported with the source file and (when available)
19	// line:column.
20	func LoadDir(dir string) ([]Check, error) {
21		entries, err := os.ReadDir(dir)
22		if err != nil {
23			if os.IsNotExist(err) {
24				return nil, nil
25			}
26			return nil, fmt.Errorf("checks: read dir %s: %w", dir, err)
27		}
28	
29		var paths []string
30		for _, e := range entries {
31			if e.IsDir() {
32				continue
33			}
34			ext := filepath.Ext(e.Name())
35			if ext != ".yaml" && ext != ".yml" {
36				continue
37			}
38			paths = append(paths, filepath.Join(dir, e.Name()))
39		}
40		sort.Strings(paths)
41	
42		out := make([]Check, 0, len(paths))
43		seen := make(map[string]string, len(paths))
44		for _, p := range paths {
45			c, err := LoadFile(p)
46			if err != nil {
47				return nil, err
48			}
49			if prior, dup := seen[c.Name]; dup {
50				return nil, fmt.Errorf("checks: duplicate check name %q in %s (also defined in %s)", c.Name, p, prior)
51			}
52			seen[c.Name] = p
53			out = append(out, c)
54		}
55		return out, nil
56	}
57	
58	// LoadFile parses a single check definition file. Unknown fields and
59	// malformed YAML are reported with file:line context.
60	func LoadFile(path string) (Check, error) {
61		data, err := os.ReadFile(path)
62		if err != nil {
63			return Check{}, fmt.Errorf("checks: read %s: %w", path, err)
64		}
65		dec := yaml.NewDecoder(bytes.NewReader(data))
66		dec.KnownFields(true)
67		var c Check
68		if err := dec.Decode(&c); err != nil {
69			return Check{}, fmt.Errorf("checks: parse %s: %w", path, err)
70		}
71		c.SourceFile = path
72		if err := c.Validate(); err != nil {
73			return Check{}, fmt.Errorf("checks: %s: %w", path, err)
74		}
75		return c, nil
76	}
77	
78	// Validate enforces required-field rules on a parsed check.
79	func (c *Check) Validate() error {
80		if c.Name == "" {
81			return fmt.Errorf("missing required field: name")
82		}
83		if c.Command == "" {
84			return fmt.Errorf("missing required field: command")
85		}
86		if c.When == "" {
87			return fmt.Errorf("missing required field: when")
88		}
89		if c.When != HookPreMerge {
90			return fmt.Errorf("unsupported hook %q (only %q is supported)", c.When, HookPreMerge)
91		}
92		return nil
93	}
94	
95	// Applies reports whether the check should run for the given context.
96	func (c *Check) Applies(ctx InvocationContext) bool {
97		a := c.AppliesTo
98		if len(a.Paths) == 0 && len(a.Labels) == 0 {
99			return true
100		}
101		for _, lbl := range a.Labels {
102			for _, b := range ctx.BeadLabels {
103				if lbl == b {
104					return true
105				}
106			}
107		}
108		for _, glob := range a.Paths {
109			for _, p := range ctx.ChangedPaths {
110				if matchPathGlob(glob, p) {
111					return true
112				}
113			}
114		}
115		return false
116	}
117	
118	func matchPathGlob(pattern, name string) bool {
119		pattern = filepath.ToSlash(pattern)
120		name = filepath.ToSlash(name)
121		if matched, _ := path.Match(pattern, name); matched {
122			return true
123		}
124		if matched, _ := path.Match(pattern, path.Base(name)); matched {
125			return true
126		}
127		if !strings.Contains(pattern, "**") {
128			return false
129		}
130		return matchDoubleStar(strings.Split(pattern, "/"), strings.Split(name, "/"))
131	}
132	
133	func matchDoubleStar(patternParts, nameParts []string) bool {
134		if len(patternParts) == 0 {
135			return len(nameParts) == 0
136		}
137		if patternParts[0] == "**" {
138			for i := 0; i <= len(nameParts); i++ {
139				if matchDoubleStar(patternParts[1:], nameParts[i:]) {
140					return true
141				}
142			}
143			return false
144		}
145		if len(nameParts) == 0 {
146			return false
147		}
148		matched, err := path.Match(patternParts[0], nameParts[0])
149		if err != nil || !matched {
150			return false
151		}
152		return matchDoubleStar(patternParts[1:], nameParts[1:])
153	}
