175	func gitChangedPaths(dir, base, head string) ([]string, error) {
176		if base == "" || base == head {
177			return nil, nil
178		}
179		out, err := exec.Command("git", "-C", dir, "diff", "--name-only", base, head).Output()
180		if err != nil {
181			return nil, err
182		}
183		lines := strings.Split(strings.TrimSpace(string(out)), "\n")
184		paths := make([]string, 0, len(lines))
185		for _, l := range lines {
186			l = strings.TrimSpace(l)
187			if l != "" {
188				paths = append(paths, l)
189			}
190		}
191		return paths, nil
192	}
